import { Injectable, inject } from '@angular/core';
import { HttpClient, HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';
import {
  AppDefinition,
  AppDefinitionListItem,
  AppSubmissionReview,
} from '../models/app-store.models';
import {
  AppDefinitionApiResponse,
  AppDefinitionListApiResponse,
  AppListQueryParams,
  AppSubmissionReviewListApiResponse,
  CreateAppDefinitionRequest,
  UpdateAppDefinitionRequest,
  AppSubmissionReviewRequest,
  InstallationListQueryParams,
} from '../models/api/app-store-api.models';
import {
  mapAppDefinitionFromApi,
  mapAppDefinitionListItemFromApi,
  mapAppSubmissionReviewFromApi,
} from '../models/api/app-store-api.mappers';
import { ApiUrlService } from '../../../core/services/api-url.service';

@Injectable({
  providedIn: 'root',
})
export class AppStoreService {
  private readonly http = inject(HttpClient);
  private readonly apiUrlService = inject(ApiUrlService);
  private readonly baseUrl: string;

  constructor() {
    this.baseUrl = `${this.apiUrlService.getCurrentApiUrl()}/telemetrystore`;
  }

  /**
   * Get all app definitions with optional filtering
   * @param params Query parameters for filtering and pagination
   */
  getApps(params: AppListQueryParams): Observable<AppDefinitionListItem[]> {
    const httpParams = this.buildGetAppsQueryParams(params);

    return this.http
      .get<AppDefinitionListApiResponse>(`${this.baseUrl}/marketplace/apps`, {
        params: httpParams,
      })
      .pipe(
        map((response) => response.items.map(mapAppDefinitionListItemFromApi)),
      );
  }

  /**
   * Get app definitions of a specific developer with optional filtering
   * @param params Query parameters for filtering and pagination
   */
  getMyApps(params: AppListQueryParams): Observable<AppDefinitionListItem[]> {
    const httpParams = this.buildGetAppsQueryParams(params);

    return this.http
      .get<AppDefinitionListApiResponse>(`${this.baseUrl}/me/apps`, {
        params: httpParams,
      })
      .pipe(
        map((response) => response.items.map(mapAppDefinitionListItemFromApi)),
      );
  }

  /**
   * Get app definitions of a specific developer with optional filtering
   * @param params Query parameters for filtering and pagination
   */
  getAppsByDeveloperId(
    developerId: string,
    params: AppListQueryParams,
  ): Observable<AppDefinitionListItem[]> {
    const httpParams = this.buildGetAppsQueryParams(params);

    return this.http
      .get<AppDefinitionListApiResponse>(
        `${this.baseUrl}/developers/${developerId}/apps`,
        {
          params: httpParams,
        },
      )
      .pipe(
        map((response) => response.items.map(mapAppDefinitionListItemFromApi)),
      );
  }

  private buildGetAppsQueryParams(params: AppListQueryParams): HttpParams {
    let httpParams = new HttpParams().set('owner', params.owner);

    if (params.offset !== undefined) {
      httpParams = httpParams.set('offset', params.offset.toString());
    }
    if (params.limit !== undefined) {
      httpParams = httpParams.set('limit', params.limit.toString());
    }
    if (params.sort !== undefined) {
      httpParams = httpParams.set('sort', params.sort);
    }
    if (params.filter !== undefined) {
      httpParams = httpParams.set('filter', params.filter);
    }

    return httpParams;
  }

  /**
   * Get app definition by ID
   * @param id App ID
   * @param developerId Optional developer ID filter
   */
  getAppById(id: string, owner: string): Observable<AppDefinition | null> {
    const httpParams = new HttpParams().set('owner', owner);

    return this.http
      .get<AppDefinitionApiResponse>(`${this.baseUrl}/marketplace/apps/${id}`, {
        params: httpParams,
      })
      .pipe(map(mapAppDefinitionFromApi));
  }

  /**
   * Create a new app definition
   * @param app App definition data
   */
  createApp(app: Partial<AppDefinition>): Observable<AppDefinition> {
    const request: CreateAppDefinitionRequest = {
      developerName: app.developerName ?? '',
      name: app.name ?? '',
      description: app.description ?? '',
      shortDescription: app.shortDescription ?? '',
      iconUrl: app.iconUrl ?? '',
      integrationPoints:
        app.integrationPoints?.map((point) => ({
          screenId: point.screenId,
          requiredPermissions: point.requiredPermissions,
          baseUrl: point.baseUrl,
        })) ?? [],
      categories: app.categories ?? [],
      tags: app.tags ?? [],
      healthCheckUrl: app.healthCheckUrl,
    };

    return this.http
      .post<AppDefinitionApiResponse>(`${this.baseUrl}/apps`, request)
      .pipe(map(mapAppDefinitionFromApi));
  }

  /**
   * Update an existing app definition's state (admin only).
   * Content fields are managed via the version submission workflow.
   * @param id App ID
   * @param state New state value
   */
  updateAppState(
    id: string,
    state: AppDefinitionApiResponse['state'],
  ): Observable<AppDefinition> {
    const request: UpdateAppDefinitionRequest = { state };

    return this.http
      .put<AppDefinitionApiResponse>(`${this.baseUrl}/apps/${id}`, request)
      .pipe(map(mapAppDefinitionFromApi));
  }

  /**
   * Get installed apps for an organisation, enriched with full app definition data.
   * Replaces the N+1 getInstallations() + getAppById() pattern on the my-installed-apps page.
   * @param orgId Organisation id
   * @param params Optional pagination params
   */
  getOrganisationInstalledApps(
    orgId: string,
    params?: InstallationListQueryParams,
  ): Observable<AppDefinitionListItem[]> {
    let httpParams = new HttpParams();
    if (params?.offset !== undefined)
      httpParams = httpParams.set('offset', params.offset.toString());
    if (params?.limit !== undefined)
      httpParams = httpParams.set('limit', params.limit.toString());
    if (params?.sort !== undefined)
      httpParams = httpParams.set('sort', params.sort);
    if (params?.filter !== undefined)
      httpParams = httpParams.set('filter', params.filter);

    return this.http
      .get<AppDefinitionListApiResponse>(
        `${this.baseUrl}/organisations/${orgId}/installed-apps`,
        { params: httpParams },
      )
      .pipe(
        map((response) => response.items.map(mapAppDefinitionListItemFromApi)),
      );
  }

  /**
   * Get submission reviews for an app (sorted desc by date, first item = most recent)
   * @param appId App ID
   */
  getSubmissionReviews(appId: string): Observable<AppSubmissionReview[]> {
    return this.http
      .get<AppSubmissionReviewListApiResponse>(
        `${this.baseUrl}/apps/${appId}/submission-reviews`,
      )
      .pipe(map((res) => res.items.map(mapAppSubmissionReviewFromApi)));
  }

  /**
   * Review an app submission (approve, reject, suspend, etc.)
   * @param id App ID
   * @param reviewData Review data including status, comments, and internal notes
   */
  reviewApp(
    id: string,
    reviewData: AppSubmissionReviewRequest,
  ): Observable<AppDefinition> {
    return this.http
      .post<AppDefinitionApiResponse>(
        `${this.baseUrl}/apps/${id}/submission-review`,
        reviewData,
      )
      .pipe(map(mapAppDefinitionFromApi));
  }
}
